[Centered covariance bound]\label{lem:centered-cov}
On the strong low--high support, for all $0\le s\le t\le T$,
\begin{equation}\label{eq:centered-cov}
\mathbb{E}|B_N^{i;j,k}(n,q;t,s)|^2\lesssim_T N^{3-6\alpha}.
\end{equation}
Moreover, for every $0<\eta\le 1/2$,
\begin{equation}\label{eq:centered-inc}
\mathbb{E}|B_N^{i;j,k}(n,q;t,s)-B_N^{i;j,k}(n,q;t',s)|^2
\lesssim_T |t-t'|^{2\eta}N^{3-6\alpha+2\eta\alpha}.
\end{equation}

[Pathwise centered fluctuations]\label{thm:pathwise-fluct}
Assume
\begin{equation}\label{eq:a-neg}
a:=6-8\alpha+2s_2+3\theta<0.
\end{equation}
Then the centered dyadic fluctuation series
\begin{equation}\label{eq:fluct-series}
B^{i;j,k}:=\sum_{N\text{ dyadic}}B_N^{i;j,k}
\end{equation}
converges almost surely in
\begin{equation}\label{eq:fluct-op-space}
\mathcal L\bigl(E_T,C_TH^{s_2-\alpha}\bigr).
\end{equation}
More precisely, for every sufficiently small $\kappa>0$ there is an almost surely finite random constant $C_\omega$ such that
\begin{equation}\label{eq:fluct-dyadic-bound}
\|B_N^{i;j,k}\|_{E_T\to C_TH^{s_2-\alpha}}
\le C_\omega N^{a/2+\kappa}
\end{equation}
for all dyadic $N$.

[Speed gap]\label{lem:speed-gap}
Fix $0<\theta<1$ and $i\neq j$. There exist $N_0$ and $c_*>0$ such that whenever $N\ge N_0$, $|\ell|\sim N$, and $|q|\le N^\theta$,
\begin{equation}\label{eq:speed-gap-minus}
|\omega_i(q+\ell)-\omega_j(\ell)|\ge c_*N^\alpha,
\end{equation}
and also
\begin{equation}\label{eq:speed-gap-plus}
\omega_i(q+\ell)+\omega_j(\ell)\ge c_*N^\alpha.
\end{equation}

